// ===== Config =====
const SUPABASE_URL = "https://vjecahooihxrofwmdbix.supabase.co";
const SUPABASE_KEY = "YOUR_SUPABASE_SERVICE_KEY";
const clientId = $('Extract Params').item.json.client_id;

if (!clientId) {
  throw new Error("client_id manquant");
}

// ===== Helpers =====
function buildQueryString(params) {
  return Object.entries(params)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
    .join("&");
}

async function fetchTable(table, extraParams = {}) {
  const params = { select: "*", ...extraParams };
  const url = `${SUPABASE_URL}/rest/v1/${table}?${buildQueryString(params)}`;
  return await this.helpers.httpRequest({
    method: "GET",
    url,
    headers: { apikey: SUPABASE_KEY },
    json: true,
  });
}

function dedupe(arr) {
  const seen = new Set();
  return arr.filter((item) => {
    const key = JSON.stringify(item);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function parseFR(val) {
  if (val === null || val === undefined || val === "") return null;
  if (typeof val === "number") return val;
  if (typeof val === "string") {
    const cleaned = val.replace(/\s/g, "").replace(",", ".");
    const n = parseFloat(cleaned);
    return isNaN(n) ? val : n;
  }
  return val;
}

function normalizeNumbers(obj) {
  if (Array.isArray(obj)) return obj.map(normalizeNumbers);
  if (obj === null || typeof obj !== "object") return obj;
  const result = {};
  for (const [k, v] of Object.entries(obj)) {
    if (/_(eur|pct|annees)$|^(vl_|taux|montant|quantite|poids|score|encours|valeur|plafond|mensualite|crd|age|nb_|revenus|tmi|allocation|anciennete)/i.test(k)) {
      result[k] = parseFR(v);
    } else if (typeof v === "object") {
      result[k] = normalizeNumbers(v);
    } else {
      result[k] = v;
    }
  }
  return result;
}

// ===== Fetch 10 tables en parallèle =====
const [
  profil, foyer, projetsObjectifs, contratsProduits, caracteristiques,
  supportsDetenus, evenements, fluxFinanciers, histoValoContrats, indicesMarche,
] = await Promise.all([
  fetchTable.call(this, "profil_client", { client_id: `eq.${clientId}` }),
  fetchTable.call(this, "foyer", { client_id: `eq.${clientId}` }),
  fetchTable.call(this, "projet_objectifs", { client_id: `eq.${clientId}` }),
  fetchTable.call(this, "contrats_produits", { client_id: `eq.${clientId}` }),
  fetchTable.call(this, "caracteristiques", { client_id: `eq.${clientId}` }),
  fetchTable.call(this, "support_detenus", { client_id: `eq.${clientId}` }),
  fetchTable.call(this, "evenements_interactions", { client_id: `eq.${clientId}`, order: "date.desc", limit: "30" }),
  fetchTable.call(this, "flux_financiers", { client_id: `eq.${clientId}`, order: "date.desc", limit: "24" }),
  fetchTable.call(this, "historique_valorisation_contrats", { client_id: `eq.${clientId}`, order: "date.desc", limit: "60" }),
  fetchTable.call(this, "indices_marche", { order: "date.desc", limit: "12" }),
]);

const clientData = {
  client_id: clientId,
  profil: normalizeNumbers(profil[0] || null),
  foyer: normalizeNumbers(dedupe(foyer)[0] || null),
  projets_objectifs: normalizeNumbers(dedupe(projetsObjectifs)),
  contrats_produits: normalizeNumbers(dedupe(contratsProduits)),
  caracteristiques: normalizeNumbers(dedupe(caracteristiques)),
  supports_detenus: normalizeNumbers(dedupe(supportsDetenus)),
  evenements: normalizeNumbers(dedupe(evenements)),
  flux_financiers: normalizeNumbers(dedupe(fluxFinanciers)),
  historique_valorisation_contrats: normalizeNumbers(dedupe(histoValoContrats)),
  indices_marche: normalizeNumbers(dedupe(indicesMarche)),
};

// ===== Peer groups hardcodés =====
const peerGroups = {
  "jeune-actif": { label: "Jeunes Actifs", metrics: { risk: 50, liquidity: 62, diversification: 20, retirement: 8, savings: 10, perf: 2.5, contracts: 2 }, social: { pct: 75, msg: "ont activé l'épargne automatique par arrondis." } },
  "entrepreneur": { label: "Entrepreneurs & Professions libérales", metrics: { risk: 65, liquidity: 55, diversification: 55, retirement: 45, savings: 22, perf: 4.5, contracts: 7 }, social: { pct: 68, msg: "utilisent un PER pour optimiser leur fiscalité." } },
  "senior-haut-tmi": { label: "Seniors patrimoniaux TMI élevée", metrics: { risk: 45, liquidity: 40, diversification: 75, retirement: 60, savings: 18, perf: 3.8, contracts: 8 }, social: { pct: 82, msg: "ont une stratégie de transmission formalisée." } },
  "retraite-transmission": { label: "Retraités patrimoniaux", metrics: { risk: 25, liquidity: 50, diversification: 65, retirement: 90, savings: 8, perf: 2.2, contracts: 6 }, social: { pct: 78, msg: "ont une clause bénéficiaire optimisée sur leur AV." } },
  "famille-proprietaire": { label: "Familles propriétaires", metrics: { risk: 40, liquidity: 45, diversification: 45, retirement: 25, savings: 12, perf: 3, contracts: 5 }, social: { pct: 72, msg: "ont souscrit une assurance décès pour protéger leur famille." } },
  "fragile": { label: "Clients financièrement fragiles", metrics: { risk: 15, liquidity: 20, diversification: 10, retirement: 5, savings: 3, perf: 0.8, contracts: 2 }, social: { pct: 65, msg: "ont activé les alertes de découvert préventives." } },
};

// ===== System prompt MODULAIRE =====
const systemPrompt = `Tu es un assistant IA pour les conseillers bancaires BNP Paribas.
Tu analyses les VRAIES données Supabase fournies et produis un dashboard ONE-PAGE.

## Règle d'or
- Utilise UNIQUEMENT les données fournies. Jamais inventer.
- Le dashboard contient EXACTEMENT 4 composants, pas plus, pas moins.
- client_profile est TOUJOURS présent en premier.
- Tu choisis les 3 autres composants les plus pertinents pour CE client selon son archetype, sa situation et ses enjeux prioritaires.

## Comment choisir les 3 autres composants (hors client_profile)

Demande-toi : "Si le conseiller n'avait que 30 secondes pour comprendre ce client, quels 3 blocs lui donneraient le plus de valeur pour le RDV ?"

Heuristiques par type de client :
- Client fragile / découverts → cash_flow + alerts + opportunities (stabiliser)
- Jeune actif équilibré sans crédit → cash_flow + alerts + opportunities (activer l'épargne)
- Famille propriétaire avec crédit → patrimony_summary + projects + alerts
- Senior patrimonial → patrimony_summary + alerts + opportunities (transmission, fiscal)
- Retraité → patrimony_summary + alerts + opportunities (succession)
- Profession libérale établie → patrimony_summary + cash_flow + opportunities
- Client avec événements de vie marquants récents (déménagement, divorce, etc.) → life_events obligatoire

Si un composant serait vide ou très pauvre en données pour ce client, ne le choisis pas.

## Format de sortie OBLIGATOIRE
JSON valide uniquement. Pas de markdown, pas de backticks, rien avant/après.

{
  "components": [
    { "type": "...", "data": {...} }
  ]
}

## Catalogue des composants disponibles

### client_profile (TOUJOURS en premier)
{
  "type": "client_profile",
  "data": {
    "name": "Prénom Nom",
    "age": number,
    "job": "string (profil.csp)",
    "risk_profile": "string (profil.profil_risque)"
  }
}

### cash_flow (12 derniers mois chronologiques ASC)
{
  "type": "cash_flow",
  "data": {
    "flows": [
      { "date": "YYYY-MM", "revenus": number, "depenses": number, "epargne": number }
    ]
  }
}

### patrimony_summary
{
  "type": "patrimony_summary",
  "data": {
    "contracts": [
      { "libelle": "string", "famille": "string", "encours_eur": number }
    ],
    "total_encours": number
  }
}

### projects
{
  "type": "projects",
  "data": {
    "projects": [
      { "label": "string", "horizon_annees": number, "montant_cible_eur": number, "priorite": "Haute|Moyenne|Basse" }
    ]
  }
}

### life_events (MAX 4, sélection éditoriale)
Priorise les événements de vie (augmentation, déménagement, changement statut). 
Évite de lister plusieurs réclamations identiques (1 max pour signaler la tendance).
{
  "type": "life_events",
  "data": {
    "events": [
      { "date": "YYYY-MM-DD", "type": "life|interaction", "title": "string court", "description": "1 phrase courte" }
    ]
  }
}

### alerts (MAX 4, hiérarchie danger > warning > info)
Titres 3-5 mots. Descriptions 1-2 phrases max, chiffres concrets.
{
  "type": "alerts",
  "data": {
    "alerts": [
      { "title": "string court", "severity": "danger|warning|info", "description": "1-2 phrases" }
    ]
  }
}

### opportunities (MAX 4)
Titres courts (nom produit/action). Rationale 1-2 phrases avec chiffre.
{
  "type": "opportunities",
  "data": {
    "opportunities": [
      { "title": "string court", "rationale": "1-2 phrases" }
    ]
  }
}

## Règles métier BNP
- Livret A plafonné 22 950€, LDDS 12 000€, PEA 150 000€
- AV à 90% fonds euro pour profil Équilibré = warning
- Clause bénéficiaire inadaptée = danger
- Découverts répétés = fragilité
- PER si TMI ≥ 30%, jamais pour retraité
- AV : avantage fiscal après 8 ans

## Contraintes absolues
- 4 composants exactement, jamais plus, jamais moins
- client_profile TOUJOURS en premier
- Français, pas d'accents dans les clés JSON
- Nombres en format JSON standard
- JSON parseable directement, pas de \\n dans les strings
- Pas de markdown dans les strings
- Réponds UNIQUEMENT avec {"components": [...]}`;

// ===== User prompt =====
const userPrompt = `Voici les données du client. Construis le dashboard modulaire le plus pertinent.

## Données du client
${JSON.stringify(clientData, null, 2)}

## Groupes de pairs disponibles
${JSON.stringify(peerGroups, null, 2)}

Réponds uniquement avec le JSON du dashboard, sans texte avant ni après.`;

// ===== Sortie =====
return [
  {
    json: {
      client_id: clientId,
      client_data: clientData,
      peer_groups: peerGroups,
      system_prompt: systemPrompt,
      user_prompt: userPrompt,
      _meta: {
        fetched_at: new Date().toISOString(),
        user_prompt_length: userPrompt.length,
        estimated_input_tokens: Math.ceil(userPrompt.length / 4),
      },
    },
  },
];

