const bedrockResponse = $input.first().json;

// Extraction texte
let rawText;
try {
  rawText = bedrockResponse.output.message.content[0].text;
} catch (err) {
  throw new Error("Réponse Bedrock inattendue: " + JSON.stringify(bedrockResponse).slice(0, 500));
}

// Nettoyage markdown
let cleaned = rawText.trim();
const fenceMatch = cleaned.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/);
if (fenceMatch) cleaned = fenceMatch[1].trim();

const firstBrace = cleaned.indexOf("{");
const lastBrace = cleaned.lastIndexOf("}");
if (firstBrace >= 0 && lastBrace > firstBrace) {
  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
}

// Parse
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error("JSON invalide Claude: " + err.message + "\nExtrait: " + cleaned.slice(0, 500));
}

if (!parsed.components || !Array.isArray(parsed.components)) {
  throw new Error("Structure invalide, 'components' manquant: " + JSON.stringify(parsed).slice(0, 300));
}

// Whitelist des types Lovable
const VALID_TYPES = new Set([
  "client_profile",
  "cash_flow",
  "patrimony_summary",
  "life_events",
  "projects",
  "alerts",
  "opportunities",
]);

const validComponents = parsed.components.filter(
  (c) => c && typeof c === "object" && c.type && c.data && VALID_TYPES.has(c.type)
);

return [
  {
    json: {
      components: validComponents,
    },
  },
];

const item = $input.first();

return [{
  json: {
    client_id: item.json.components?.find(c => c.type === 'client_profile')?.data?.name ?? 'unknown',
    payload: item.json
  }
}];
